  .slide-wave { background: var(--bg-dark); }
  .slide-wave .slide-label { color: var(--accent-amber); }
  .slide-wave .wave-events {
    display: flex;
    flex-direction: column;
    gap: 20px;
    margin-bottom: 28px;
  }
  .slide-wave .wave-event {
    background: var(--bg-card);
    border-radius: 16px;
    padding: 28px 32px;
    display: flex;
    gap: 20px;
    align-items: center;
    border-left: 4px solid;
  }
  .slide-wave .wave-trigger {
    flex: 1;
    font-size: 19px;
    color: var(--text-secondary);
    line-height: 1.5;
  }
  .slide-wave .wave-trigger strong {
    color: var(--text-primary);
    font-weight: 700;
    display: block;
    margin-bottom: 4px;
    font-size: 21px;
  }
  .slide-wave .wave-arrow {
    font-size: 28px;
    flex-shrink: 0;
  }
  .slide-wave .wave-response {
    flex: 1;
    font-size: 20px;
    font-weight: 600;
    line-height: 1.5;
  }
  .slide-wave .wave-insight {
    background: rgba(245,158,11,0.08);
    border: 1px solid rgba(245,158,11,0.25);
    border-radius: 16px;
    padding: 32px 36px;
    font-size: 24px;
    font-weight: 500;
    color: var(--text-primary);
    line-height: 1.6;
  }
